/// <summary>
/// Config import
/// </summary>
public class ETG_Acu_EcoResConfigImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_EcoResConfigImport  configImport;

    configImport = ETG_Acu_EcoResConfigImport::construct();

    if (configImport.prompt())
    {
        configImport.runOperation();
    }
}

public static ETG_Acu_EcoResConfigImport construct()
{
    return new ETG_Acu_EcoResConfigImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    EcoResProductConfigurationEntity    config;
    EcoResConfigurationName             configName;

    configName = conpeek(_con, 1);

    select firstonly config
        where config.ConfigurationId == configName;

    if (!config)
    {
        config.ConfigurationId   = conpeek(_con, 1);
        config.insert();
    }
}

/// <summary>
/// Import colors
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpConfig";

    return ret;
}
